#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, phi;
        scanf("%lld %lld", &N, &phi);
        // calculate prime factors
        for (long long i = 2; i * i <= N; i++) {
            if (N % i == 0) {
                int e = 0;
                while (N % i == 0) {
                    N /= i;
                    e++;
                }
                printf("%d %d\n", i, e);
            }
        }
        if (N > 1) {
            printf("%lld 1\n", N);
        }
    }
    return 0;
}

